if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
var body = $input.first().json.body || $input.first().json;
var auth = body.auth_key || '';
if (auth !== $env.GDA_API_KEY_2026) return [{json:{error:'Unauthorized',direction:'none'}}];

var direction = body.direction || 'unknown';
var source = body.source || 'unknown';
var planId = body.plan_id || null;
var oppId = body.opp_id || null;
var changes = body.changes || {};

// Determine sync direction
if (direction === 'cap_to_opp' && planId) {
  // Capture plan was saved -> sync key fields to gda_opportunity_tracker
  var fields = [];
  var setClauses = [];
  var opp = changes.opportunity || '';
  var agency = changes.agency || '';
  var cv = changes.total_contract_value || changes.contract_value || '';
  var stage = changes.stage || '';
  var pwin = changes.pwin || '';
  var sol = changes.solicitation_number || '';

  if (opp) { setClauses.push("opp_title = '" + opp.replace(/'/g,"''") + "'"); fields.push('opp_title'); }
  if (agency) { setClauses.push("agency = '" + agency.replace(/'/g,"''") + "'"); fields.push('agency'); }
  if (cv) { setClauses.push("estimated_value = " + parseFloat(String(cv).replace(/[$,]/g,''))); fields.push('estimated_value'); }
  if (pwin) { setClauses.push("gda_score = " + parseInt(pwin)); fields.push('gda_score'); }
  if (sol) { setClauses.push("solicitation_number = '" + sol.replace(/'/g,"''") + "'"); fields.push('solicitation_number'); }

  setClauses.push("updated_at = NOW()");

  // Find matching opp by plan's opportunity name or solicitation
  var whereClause = oppId ? 'id = ' + oppId : "(opp_title ILIKE '" + (opp||'NOMATCH').replace(/'/g,"''") + "' OR solicitation_number = '" + (sol||'NOMATCH').replace(/'/g,"''") + "')";

  var sql = 'UPDATE gda_opportunity_tracker SET ' + setClauses.join(', ') + ' WHERE ' + whereClause;

  return [{json:{direction:'cap_to_opp', sql:sql, plan_id:planId, fields_synced:fields, source:source, timestamp:new Date().toISOString()}}];
}
else if (direction === 'opp_to_cap' && oppId) {
  // Opp tracker was updated -> sync to linked capture plan
  var capChanges = {};
  if (changes.opp_title) capChanges.opportunity = changes.opp_title;
  if (changes.agency) capChanges.agency = changes.agency;
  if (changes.estimated_value) capChanges.total_contract_value = String(changes.estimated_value);
  if (changes.gda_score) capChanges.pwin = String(changes.gda_score);
  if (changes.response_deadline) capChanges.rfp_date = changes.response_deadline;
  if (changes.solicitation_number) capChanges.solicitation_number = changes.solicitation_number;

  var jsonPatch = JSON.stringify(capChanges).replace(/'/g,"''");
  var sql2 = "UPDATE gda_capture_plans SET plan_data = plan_data || '" + jsonPatch + "'::jsonb WHERE opportunity ILIKE '%" + (changes.opp_title||'NOMATCH').replace(/'/g,"''") + "%' OR id = " + (planId || 0);

  return [{json:{direction:'opp_to_cap', sql:sql2, opp_id:oppId, fields_synced:Object.keys(capChanges), source:source, timestamp:new Date().toISOString()}}];
}

return [{json:{direction:'none', error:'Invalid direction or missing IDs', source:source}}];
